class Networking {
    private let environment: Environment
    
    init(environment: Environment = .development) {
        self.environment = environment
    }
    
    func GET(_ endpoint: String, completion: @escaping ([String : Any]?, Error?) -> Void) {
        guard let url = URL(string: "\(environment.baseUrl)/\(endpoint)") else { return }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(nil, error)
                return
            }
            
            if let data = data, let json = try? JSONSerialization.jsonObject(with: data, options: []) as? [String : Any] {
                completion(json, nil)
                return
            }
            
            completion(nil, nil)
        }.resume()
    }
    
    func POST(_ endpoint: String, body: [String : Any], completion: @escaping ([String : Any]?, Error?) -> Void) {
        guard let url = URL(string: "\(environment.baseUrl)/\(endpoint)") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = try? JSONSerialization.data(withJSONObject: body, options: [])
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(nil, error)
                return
            }
            
            if let data = data, let json = try? JSONSerialization.jsonObject(with: data, options: []) as? [String : Any] {
                completion(json, nil)
                return
            }
            
            completion(nil, nil)
        }.resume()
    }
}

class AuthenticatedNetworking {
    private let networking: Networking
    
    init(networking: Networking = Networking()) {
        self.networking = networking
    }
    
    func login(username: String, password: String, completion: @escaping ([String : Any]?, Error?) -> Void) {
        let body = ["username": username, "password": password]
        networking.POST("login", body: body, completion: completion)
